import { Link as RemixLink, useNavigate, useParams } from "@remix-run/react";
import type { LinkProps } from "@remix-run/react";
import { useCallback, forwardRef } from "react";

export function useLocalePath(path: string, locale?: string) {
  const { lang } = useParams<{ lang: string }>();
  const effectiveLocale = locale || lang || "en";
  const cleanPath = path.startsWith("/") ? path : `/${path}`;
  return `/${effectiveLocale}${cleanPath}`;
}

export function useLocalizedPath() {
  const { lang } = useParams<{ lang: string }>();
  const locale = lang || "en";

  return useCallback(
    (path: string) => {
      const cleanPath = path.startsWith("/") ? path : `/${path}`;
      return `/${locale}${cleanPath}`;
    },
    [locale]
  );
}

export const LocalizedLink = forwardRef<HTMLAnchorElement, LinkProps>(
  function LocalizedLink({ to, ...rest }, ref) {
    const localePath = useLocalePath(String(to));
    return <RemixLink to={localePath} {...rest} ref={ref} />;
  }
);

export function useLocalizedNavigate() {
  const navigate = useNavigate();
  const { lang } = useParams<{ lang: string }>();
  const locale = lang || "en";

  return useCallback(
    (path: string, options?: { replace?: boolean }) => {
      const cleanPath = path.startsWith("/") ? path : `/${path}`;
      if (cleanPath.startsWith(`/${locale}/`) || cleanPath === `/${locale}`) {
        navigate(cleanPath, options);
      } else {
        navigate(`/${locale}${cleanPath}`, options);
      }
    },
    [navigate, locale]
  );
}

export function useLocalizedBack(fallbackPath: string) {
  const navigate = useNavigate();
  const { lang } = useParams<{ lang: string }>();
  const locale = lang || "en";

  return useCallback(() => {
    if (
      typeof window !== "undefined" &&
      Number(window.history.state?.idx || 0) > 0
    ) {
      navigate(-1);
      return;
    }

    const cleanPath = fallbackPath.startsWith("/")
      ? fallbackPath
      : `/${fallbackPath}`;
    if (cleanPath.startsWith(`/${locale}/`) || cleanPath === `/${locale}`) {
      navigate(cleanPath);
    } else {
      navigate(`/${locale}${cleanPath}`);
    }
  }, [fallbackPath, navigate, locale]);
}
